import{_ as t,o as d,i as o,ad as n}from"./chunks/framework.URtSBH_h.js";const f=JSON.parse('{"title":"Integration API reference","description":"Generated API reference for @pikacss/integration from exported surface and JSDoc.","frontmatter":{"title":"Integration API reference","description":"Generated API reference for @pikacss/integration from exported surface and JSDoc.","outline":[2,3],"relatedPackages":["@pikacss/integration"],"relatedSources":["packages/integration/src/ctx.ts","packages/integration/src/index.ts","packages/integration/src/types.ts"],"category":"api","order":30},"headers":[],"relativePath":"api/integration.md","filePath":"api/integration.md"}'),r={name:"api/integration.md"};function a(i,e,c,s,l,g){return d(),o("div",null,[...e[0]||(e[0]=[n('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /api/integration.md for this page in Markdown format</div><h1 id="integration-api-reference" tabindex="-1">Integration API reference <a class="header-anchor" href="#integration-api-reference" aria-label="Permalink to “Integration API reference”">​</a></h1><details><summary>Source information</summary><ul><li>Package: <code>@pikacss/integration</code></li><li>Generated from the exported surface and JSDoc in <code>packages/integration/src/index.ts</code>.</li><li>Source files: <code>packages/integration/src/ctx.ts</code>, <code>packages/integration/src/index.ts</code>, <code>packages/integration/src/types.ts</code></li></ul></details><h2 id="package-summary" tabindex="-1">Package summary <a class="header-anchor" href="#package-summary" aria-label="Permalink to “Package summary”">​</a></h2><p>Build-tool integration context Re-exports the public surface of <a href="/api/core.html"><code>@pikacss/core</code></a>.</p><p>Use <a href="/integrations/unplugin.html">Unplugin integration</a> when you need conceptual usage guidance instead of exact symbol lookup.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to “Functions”">​</a></h2><h3 id="function-createctx-options" tabindex="-1">createCtx(options) <a class="header-anchor" href="#function-createctx-options" aria-label="Permalink to “createCtx(options)”">​</a></h3><p>Creates an <code>IntegrationContext</code> that wires together config loading, engine initialization, source file transformation, and codegen output.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>options</code></td><td><code>IntegrationContextOptions</code></td><td>The integration configuration including paths, function name, scan globs, and codegen settings.</td></tr></tbody></table><p><strong>Returns:</strong> <code>IntegrationContext</code> - A fully constructed <code>IntegrationContext</code>. Call <code>setup()</code> on the returned context before using transforms.</p><p>The context uses reactive signals internally so that computed paths (CSS and TS codegen file paths) automatically update when <code>cwd</code> changes. The <code>setup()</code> method must be called before any transform or codegen operations - transform calls automatically await the pending setup promise.</p><br><br><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to “Types”">​</a></h2><h3 id="interface-fnutils" tabindex="-1">FnUtils <a class="header-anchor" href="#interface-fnutils" aria-label="Permalink to “FnUtils”">​</a></h3><p>Classifier and regex utilities for recognizing all <code>pika()</code> function call variants in source code.</p><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>isNormal</code></td><td><code>(fnName: string) =&gt; boolean</code></td><td>Returns <code>true</code> if the given function name is a normal call (output format determined by <code>transformedFormat</code>).</td><td>—</td></tr><tr><td><code>isForceString</code></td><td><code>(fnName: string) =&gt; boolean</code></td><td>Returns <code>true</code> if the given function name forces string output (e.g., <code>pika.str</code>).</td><td>—</td></tr><tr><td><code>isForceArray</code></td><td><code>(fnName: string) =&gt; boolean</code></td><td>Returns <code>true</code> if the given function name forces array output (e.g., <code>pika.arr</code>).</td><td>—</td></tr><tr><td><code>isPreview</code></td><td><code>(fnName: string) =&gt; boolean</code></td><td>Returns <code>true</code> if the given function name is a preview variant (e.g., <code>pikap</code>, <code>pikap.str</code>).</td><td>—</td></tr><tr><td><code>RE</code></td><td><code>RegExp</code></td><td>A compiled global regex that matches all recognized function call variants, including bracket-notation accessors.</td><td>—</td></tr></tbody></table><p><strong>Remarks:</strong></p><p>The function name is configurable via <code>IntegrationContextOptions.fnName</code>, so all variants (<code>.str</code>, <code>.arr</code>, preview <code>p</code> suffix, bracket notation) are derived dynamically from that base name.</p><br><br><h3 id="interface-integrationcontext" tabindex="-1">IntegrationContext <a class="header-anchor" href="#interface-integrationcontext" aria-label="Permalink to “IntegrationContext”">​</a></h3><p>The main build-tool integration context that bridges the PikaCSS engine with bundler plugins.</p><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>cwd</code></td><td><code>string</code></td><td>The current working directory. Can be updated at runtime (e.g., when the project root changes).</td><td>—</td></tr><tr><td><code>currentPackageName</code></td><td><code>string</code></td><td>The npm package name of the integration consumer, used in generated file headers and module declarations.</td><td>—</td></tr><tr><td><code>fnName</code></td><td><code>string</code></td><td>The base function name recognized in source transforms (e.g., <code>&#39;pika&#39;</code>).</td><td>—</td></tr><tr><td><code>transformedFormat</code></td><td><code>&#39;string&#39; | &#39;array&#39;</code></td><td>The default output format for normal <code>pika()</code> calls: <code>&#39;string&#39;</code> or <code>&#39;array&#39;</code>.</td><td>—</td></tr><tr><td><code>cssCodegenFilepath</code></td><td><code>string</code></td><td>Absolute path to the generated CSS output file, computed from <code>cwd</code> and the configured relative path.</td><td>—</td></tr><tr><td><code>tsCodegenFilepath</code></td><td><code>string | Nullish</code></td><td>Absolute path to the generated TypeScript declaration file, or <code>null</code> if TypeScript codegen is disabled.</td><td>—</td></tr><tr><td><code>hasVue</code></td><td><code>boolean</code></td><td>Whether the <code>vue</code> package is installed in the project, used to include Vue-specific type declarations in codegen.</td><td>—</td></tr><tr><td><code>resolvedConfig</code></td><td><code>EngineConfig | Nullish</code></td><td>The loaded engine configuration object, or <code>null</code> if loading failed or no config was found.</td><td>—</td></tr><tr><td><code>resolvedConfigPath</code></td><td><code>string | Nullish</code></td><td>Absolute path to the resolved config file on disk, or <code>null</code> for inline configs or when no config was loaded.</td><td>—</td></tr><tr><td><code>resolvedConfigContent</code></td><td><code>string | Nullish</code></td><td>Raw string content of the config file, or <code>null</code> for inline configs or when no config was loaded.</td><td>—</td></tr><tr><td><code>loadConfig</code></td><td><code>() =&gt; Promise&lt;LoadedConfigResult&gt;</code></td><td>Loads (or reloads) the engine configuration from disk or inline source, updating <code>resolvedConfig</code>, <code>resolvedConfigPath</code>, and <code>resolvedConfigContent</code>.</td><td>—</td></tr><tr><td><code>usages</code></td><td><code>Map&lt;string, UsageRecord[]&gt;</code></td><td>Map from source file ID to the list of <code>UsageRecord</code> entries extracted during transforms. Keyed by the file path relative to <code>cwd</code>.</td><td>—</td></tr><tr><td><code>previewUsages</code></td><td><code>Map&lt;string, UsageRecord[]&gt;</code></td><td>Map from source file ID to preview-only <code>UsageRecord</code> entries (from <code>pikap()</code> calls). Only these drive TypeScript preview overload generation.</td><td>—</td></tr><tr><td><code>hooks</code></td><td><code>{ styleUpdated: ReturnType&lt;typeof createEventHook&lt;void&gt;&gt; tsCodegenUpdated: ReturnType&lt;typeof createEventHook&lt;void&gt;&gt; }</code></td><td>Event hooks for notifying plugins when generated outputs need refreshing. <code>styleUpdated</code> fires on CSS changes; <code>tsCodegenUpdated</code> fires on TypeScript declaration changes.</td><td>—</td></tr><tr><td><code>engine</code></td><td><code>Engine</code></td><td>The initialized PikaCSS engine instance. Throws if accessed before <code>setup()</code> completes.</td><td>—</td></tr><tr><td><code>transformFilter</code></td><td><code>{ include: string[] exclude: string[] }</code></td><td>Glob patterns for the bundler&#39;s transform pipeline, derived from the scan config with codegen files excluded.</td><td>—</td></tr><tr><td><code>transform</code></td><td><code>(code: string, id: string) =&gt; Promise&lt;{ code: string, map: SourceMap } | Nullish&gt;</code></td><td>Processes a source file by extracting <code>pika()</code> calls, resolving them through the engine, and replacing them with computed output. Returns the transformed code and source map, or <code>null</code> if no calls were found.</td><td>—</td></tr><tr><td><code>getCssCodegenContent</code></td><td><code>() =&gt; Promise&lt;string | Nullish&gt;</code></td><td>Generates the full CSS output string, including layer declarations, preflights, and all atomic styles collected from transforms.</td><td>—</td></tr><tr><td><code>getTsCodegenContent</code></td><td><code>() =&gt; Promise&lt;string | Nullish&gt;</code></td><td>Generates the full TypeScript declaration content for <code>pika.gen.ts</code>, or <code>null</code> if TypeScript codegen is disabled.</td><td>—</td></tr><tr><td><code>writeCssCodegenFile</code></td><td><code>() =&gt; Promise&lt;void&gt;</code></td><td>Generates and writes the CSS codegen file to disk at <code>cssCodegenFilepath</code>.</td><td>—</td></tr><tr><td><code>writeTsCodegenFile</code></td><td><code>() =&gt; Promise&lt;void&gt;</code></td><td>Generates and writes the TypeScript codegen file to disk at <code>tsCodegenFilepath</code>. No-op if TypeScript codegen is disabled.</td><td>—</td></tr><tr><td><code>fullyCssCodegen</code></td><td><code>() =&gt; Promise&lt;void&gt;</code></td><td>Scans all matching source files, collects usages via transform, then writes the CSS codegen file. Used for full rebuilds.</td><td>—</td></tr><tr><td><code>setupPromise</code></td><td><code>Promise&lt;void&gt; | null</code></td><td>The pending setup promise while initialization is in progress, or <code>null</code> when idle. Transform calls await this before proceeding.</td><td>—</td></tr><tr><td><code>setup</code></td><td><code>() =&gt; Promise&lt;void&gt;</code></td><td>Initializes (or reinitializes) the context by clearing state, loading config, creating the engine, and wiring up dev hooks. Returns a promise that resolves when setup is complete.</td><td>—</td></tr></tbody></table><p><strong>Remarks:</strong></p><p>Created via <code>createCtx()</code>. The context manages the full build lifecycle: config loading, engine initialization, source file transformation, usage tracking, and output file generation. All transform and codegen calls automatically await <code>setup()</code> completion before proceeding.</p><br><br><h3 id="interface-integrationcontextoptions" tabindex="-1">IntegrationContextOptions <a class="header-anchor" href="#interface-integrationcontextoptions" aria-label="Permalink to “IntegrationContextOptions”">​</a></h3><p>Configuration options for creating an integration context.</p><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>cwd</code></td><td><code>string</code></td><td>The working directory used to resolve relative paths for config files, codegen outputs, and source scanning.</td><td>—</td></tr><tr><td><code>currentPackageName</code></td><td><code>string</code></td><td>The npm package name of the integration consumer (e.g., <code>&#39;@pikacss/unplugin&#39;</code>), embedded in generated file headers and import paths.</td><td>—</td></tr><tr><td><code>scan</code></td><td><code>{ include: string[] exclude: string[] }</code></td><td>Glob patterns controlling which source files are scanned for <code>pika()</code> calls. <code>include</code> specifies files to process; <code>exclude</code> specifies files to skip.</td><td>—</td></tr><tr><td><code>configOrPath</code></td><td><code>EngineConfig | string | Nullish</code></td><td>The engine configuration object, a path to a config file, or <code>null</code>/<code>undefined</code> to trigger auto-discovery of <code>pika.config.*</code> files.</td><td>—</td></tr><tr><td><code>fnName</code></td><td><code>string</code></td><td>The base function name to recognize in source code (e.g., <code>&#39;pika&#39;</code>). All variants (<code>.str</code>, <code>.arr</code>, preview) are derived from this name.</td><td>—</td></tr><tr><td><code>transformedFormat</code></td><td><code>&#39;string&#39; | &#39;array&#39;</code></td><td>Controls the default output format of normal <code>pika()</code> calls: <code>&#39;string&#39;</code> produces a space-joined class string, <code>&#39;array&#39;</code> produces a string array.</td><td>—</td></tr><tr><td><code>tsCodegen</code></td><td><code>false | string</code></td><td>Path to the generated TypeScript declaration file (<code>pika.gen.ts</code>), or <code>false</code> to disable TypeScript codegen entirely.</td><td>—</td></tr><tr><td><code>cssCodegen</code></td><td><code>string</code></td><td>Path to the generated CSS output file (e.g., <code>&#39;pika.gen.css&#39;</code>).</td><td>—</td></tr><tr><td><code>autoCreateConfig</code></td><td><code>boolean</code></td><td>When <code>true</code>, automatically scaffolds a default <code>pika.config.js</code> file if no config file is found.</td><td>—</td></tr></tbody></table><p><strong>Remarks:</strong></p><p>These options are set by bundler plugin adapters (Vite, webpack, Nuxt) and are not typically configured by end users directly.</p><br><br><h3 id="type-loadedconfigresult" tabindex="-1">LoadedConfigResult <a class="header-anchor" href="#type-loadedconfigresult" aria-label="Permalink to “LoadedConfigResult”">​</a></h3><p>Discriminated union representing the outcome of loading an engine configuration file.</p><p><strong>Remarks:</strong></p><p>Three shapes are possible: an inline config (no file), a successfully loaded file-based config, or a failed/missing load (all fields <code>null</code>). The <code>file</code> and <code>content</code> fields are populated only when the config was loaded from disk, enabling hot-reload detection.</p><br><br><h3 id="interface-usagerecord" tabindex="-1">UsageRecord <a class="header-anchor" href="#interface-usagerecord" aria-label="Permalink to “UsageRecord”">​</a></h3><p>Records a single <code>pika()</code> call result, pairing the resolved atomic style IDs with the original call arguments.</p><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>atomicStyleIds</code></td><td><code>string[]</code></td><td>The list of atomic CSS class names generated by the engine for this call.</td><td>—</td></tr><tr><td><code>params</code></td><td><code>Parameters&lt;Engine[&#39;use&#39;]&gt;</code></td><td>The original arguments passed to <code>engine.use()</code>, preserved for TypeScript codegen overload generation.</td><td>—</td></tr></tbody></table><p><strong>Remarks:</strong></p><p>Each source file may produce multiple <code>UsageRecord</code> entries — one per <code>pika()</code> call site. These records drive both CSS output (via <code>atomicStyleIds</code>) and IDE preview overloads (via <code>params</code>).</p><br><br><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to “Next”">​</a></h2><ul><li><a href="/integrations/unplugin.html">Unplugin integration</a></li><li><a href="/api/unplugin.html">Unplugin API reference</a></li><li><a href="/api/">API reference overview</a></li></ul>',51)])])}const h=t(r,[["render",a]]);export{f as __pageData,h as default};
